import{_ as n,c as t,a1 as a,o as r}from"./chunks/framework.BDxlaA_J.js";const h=JSON.parse('{"title":"Scanning a Target Network","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/2-scanning-networks/0-Scanning-a-Target-Network.md","filePath":"categories/ethical-hacking-labs/2-scanning-networks/0-Scanning-a-Target-Network.md"}'),i={name:"categories/ethical-hacking-labs/2-scanning-networks/0-Scanning-a-Target-Network.md"};function s(o,e,c,g,l,p){return r(),t("div",null,e[0]||(e[0]=[a('<h1 id="scanning-a-target-network" tabindex="-1">Scanning a Target Network <a class="header-anchor" href="#scanning-a-target-network" aria-label="Permalink to &quot;Scanning a Target Network&quot;">​</a></h1><p>Network Scanning refers to a set of procedures performed to identify hosts, ports, and services running in a network.</p><p>The purpose of network scanning is as follows:</p><ul><li>Recognize available UDP and TCP network services running on the targeted hosts.</li><li>Recognize filtering systems between the user and the targeted hosts.</li><li>Determine the operating systems (OSs) in use by assessing IP responses.</li><li>Evaluate the target host&#39;s TCP sequence number predictability to determine sequence prediction attack and TCP spoofing.</li></ul><p>Source: <a href="https://www.techopedia.com/definition/16124/network-scanning" target="_blank" rel="noreferrer">https://www.techopedia.com/definition/16124/network-scanning</a></p>',5)]))}const k=n(i,[["render",s]]);export{h as __pageData,k as default};
